// generar_253_dosis_rapida_y_editar_enfermedades.js
// CHIQUI Entre Señales — Dosis rápida desde Novedades + edición de enfermedades
//
// Dos ajustes UX importantes tras probar con dosis múltiples:
//
// 1) DOSIS RÁPIDA desde la novedad del dashboard.
//    Antes: tocar la novedad llevaba a /registro-diario, donde para
//    registrar la segunda dosis del día había que desmarcar "Recibió
//    medicamento", volver a marcar, elegir el medicamento del mini-
//    modal y guardar todo el registro. Seis pasos para algo diario.
//    Ahora: tocar la novedad REGISTRA la dosis en 1 tap y refresca.
//
//    Además, cambia la ARQUITECTURA de la novedad de medicamentos:
//    - Antes era UNA novedad para todos los pendientes ("Rimadyl y
//      Meloxicam").
//    - Ahora es UNA novedad POR CADA DOSIS PENDIENTE. Con Rimadyl 3
//      veces al día y Meloxicam 1 vez al día, se muestran 4 novedades
//      independientes que puedes ir marcando una por una:
//        💊 Le toca la dosis 1 de 3 de Rimadyl a Luna.  [✓ Registrar dosis 1]
//        💊 Le toca la dosis 2 de 3 de Rimadyl a Luna. (Van 1/3 hoy)  [✓ Registrar dosis 2]
//        💊 Le toca la dosis 3 de 3 de Rimadyl a Luna. (Van 2/3 hoy)  [✓ Registrar dosis 3]
//        💊 ¿Ya le diste Meloxicam a Luna hoy? (1 vez al día)  [✓ Ya se lo di]
//
//    El texto es adaptativo según si el tratamiento es único o
//    múltiple. Cada novedad conserva el 'onAccion' que la resuelve
//    sin navegar; la ✕ sigue cerrándola sin registrar (efímera:
//    reaparece al volver al dashboard).
//
//    Este flujo NO reemplaza el registro diario: si el usuario quiere
//    revisar más cosas del día, puede seguir yendo por /registro-diario.
//    Solo elimina la fricción cuando solo quiere confirmar una dosis.
//
// 2) ENFERMEDADES editables (faltaba, solo se podían crear).
//    - Botón ⋮ en cada tarjeta de enfermedad (mismo patrón que
//      vacunas, antiparasitarios y medicamentos).
//    - Editar precarga los campos y guarda con UPDATE (foto se
//      preserva; si se sube una nueva, la reemplaza).
//    - Eliminar con confirmación.
//    - Título del modal cambia a "🏥 Editar diagnóstico".
//
// No hay SQL. Este script se construye sobre el 252 (o superior).
//
// Uso:
//   node generar_253_dosis_rapida_y_editar_enfermedades.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/Novedades.tsx",
    base64: ""
  },
  {
    ruta: "app/dashboard/page.tsx",
    base64: ""
  },
  {
    ruta: "components/DashboardContenido.tsx",
    base64: ""
  },
  {
    ruta: "app/prevencion/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 4 archivos escritos. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
